  describe('invariant examples', () => {
    it("register then resolve", async () => {
      const storage = createInMemoryStorage();
      const registerResult0 = await interpret(webhookDispatchProviderHandler.register({ name: "step-run-handler", kind: "step-run", eventTypes: "[\"step.completed\"]", config: "{\"timeout\": 30}" }), storage);
      expect(registerResult0.variant).toBe("ok");
      let provider = registerResult0.output["provider"];
      let p = provider;
      const thenResult0 = await interpret(webhookDispatchProviderHandler.resolve({ eventType: "step.completed" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("register then dispatch", async () => {
      const storage = createInMemoryStorage();
      const registerResult0 = await interpret(webhookDispatchProviderHandler.register({ name: "automation-rule-handler", kind: "automation", eventTypes: "[\"order.created\"]", config: "{\"ruleSet\": \"commerce\"}" }), storage);
      expect(registerResult0.variant).toBe("ok");
      let provider = registerResult0.output["provider"];
      let p = provider;
      const thenResult0 = await interpret(webhookDispatchProviderHandler.dispatch({ eventType: "order.created", payload: "{\"orderId\": \"ord-1\", \"total\": 50.00}" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("deregister removes provider", async () => {
      const storage = createInMemoryStorage();
      const registerResult0 = await interpret(webhookDispatchProviderHandler.register({ name: "forward-handler", kind: "forward", eventTypes: "[\"audit.event\"]", config: "{\"endpoint\": \"https://audit.example.com/ingest\"}" }), storage);
      expect(registerResult0.variant).toBe("ok");
      let provider = registerResult0.output["provider"];
      let p = provider;
      const thenResult0 = await interpret(webhookDispatchProviderHandler.deregister({ name: "forward-handler" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

